INSERT INTO workshops (id, title, chef, level, price, max_capacity, category, emoji, image, description) VALUES
(1, 'โครยซองต์ มาสเตอร์คลาส',      'เชฟ พงศธร',  'ระดับกลาง', 3500, 12, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://images.unsplash.com/photo-1612366747681-e4ca6992b1e9?w=500&auto=format&fit=crop&q=60&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxzZWFyY2h8MTB8fENyb2lzc2FudCUyME1hc3RlcmNsYXNzfGVufDB8fDB8fHww', 'เรียนรู้ความลับของเลเยอร์ที่สมบูรณ์แบบและการนวดเนยสไตล์ฝรั่งเศสขนานแท้'),
(2, 'เวิร์กชอปโดนัทเคลือบน้ำตาล', 'เชฟ นภัสสร', 'เริ่มต้น',   2800, 15, 'โดนัทและฟริตเตอร์',   '🍩', 'https://images.unsplash.com/photo-1551024601-bec78aea704b?auto=format&fit=crop&w=600&q=80', 'สนุกกับการปั้นและเคลือบโดนัทหลากรสชาติ พร้อมเทคนิคการทอดให้ฟูนุ่ม'),
(3, 'ขนมปังซาวร์โดว์เบื้องต้น',    'เชฟ ธนวัฒน์', 'เริ่มต้น',  2500, 10, 'ขนมปังอบ',            '🍞', 'https://images.unsplash.com/photo-1549931319-a545dcf3bc73?auto=format&fit=crop&w=600&q=80', 'เริ่มต้นทำขนมปังซาวร์โดว์ตั้งแต่การเลี้ยงหัวเชื้อจนถึงการอบให้ได้เปลือกกรอบ'),
(4, 'ห้องปฏิบัติการมาการอง',        'เชฟ ปาริชาต', 'ระดับกลาง', 4200, 10, 'เค้กและขนมหวาน',     '🎂', 'https://images.unsplash.com/photo-1569864358642-9d1684040f43?auto=format&fit=crop&w=600&q=80', 'ฝึกทำมาการองฝรั่งเศสให้ได้ผิวเรียบ เท้าสวย พร้อมไส้ครีมหลากรส'),
(5, 'พรีเมียมคัพเค้กและบัตเตอร์ครีมดอกไม้', 'เชฟ นภัสสร', 'เริ่มต้น',   3000, 12, 'เค้กและขนมหวาน',     '🧁', 'https://media.istockphoto.com/id/1323793831/photo/buttercream-flower-cupcakes-recipe-photography.webp?a=1&b=1&s=612x612&w=0&k=20&c=OiYKfVFCOuXfmotisixp6f6Q0Pk4UEselbzxmQx8bgU=', 'เรียนรู้การอบคัพเค้กเนื้อนุ่มและเทคนิคการบีบบัตเตอร์ครีมดอกไม้สไตล์พรีเมียม'),
(6, 'มาสเตอร์คลาสครัวซองต์ช็อกโกแลตทูโทน', 'เชฟ พงศธร', 'ระดับกลาง', 3800, 10, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://images.unsplash.com/photo-1587080414086-57cef7f2641d?w=500&auto=format&fit=crop&q=60&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxzZWFyY2h8MTZ8fFR3by10b25lJTIwY2hvY29sYXRlJTIwY3JvaXNzYW50JTIwbWFzdGVyY2xhc3N8ZW58MHx8MHx8fDA%3D', 'ต่อยอดจากครัวซองต์คลาสสิก สู่การทำแป้งช็อกโกแลตทูโทนและสอดไส้ช็อกโกแลตพรีเมียม'),
(7, 'พรีเมียมบับก้าช็อกโกแลตโฮมเมด', 'เชฟ ธนวัฒน์', 'ระดับกลาง', 3100, 12, 'ขนมปังอบ',            '🍞', 'https://images.unsplash.com/photo-1586806720715-f5a2610d78f0?w=500&auto=format&fit=crop&q=60&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxzZWFyY2h8MTV8fFByZW1pdW0lMjBob21lbWFkZSUyMEJhYmthJTIwY2hvY29sYXRlfGVufDB8fDB8fHww', 'ทำขนมปังถัก Babka ไส้ช็อกโกแลตเบลเยียมเข้มข้น แป้งเหนียวนุ่มชุ่มฉ่ำเนย'),
(8, 'ขนมปังฟอกาชเชียสมุนไพรอิตาเลียน', 'เชฟ ธนวัฒน์', 'เริ่มต้น',   2200, 15, 'ขนมปังอบ',            '🍞', 'https://plus.unsplash.com/premium_photo-1700326967545-91adcec6af2a?w=500&auto=format&fit=crop&q=60&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxzZWFyY2h8OXx8SXRhbGlhbiUyMGhlcmIlMjBmb2NhY2NpYSUyMGJyZWFkfGVufDB8fDB8fHww', 'สนุกกับการตกแต่งหน้าขนมปังฟอกาชเชียด้วยสมุนไพรสด มะเขือเทศเชอร์รี และน้ำมันมะกอกเกรดพรีเมียม'),
(9, 'โดนัทสไตล์ญี่ปุ่นครีมสดวานิลลา', 'เชฟ นภัสสร', 'เริ่มต้น',   2900, 12, 'โดนัทและฟริตเตอร์',   '🍩', 'https://images.unsplash.com/photo-1582215669338-6cfdb76bca45?w=500&auto=format&fit=crop&q=60&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxzZWFyY2h8MTh8fEphcGFuZXNlLXN0eWxlJTIwZG9udXQlMjB3aXRoJTIwdmFuaWxsYSUyMGZyZXNoJTIwY3JlYW0ufGVufDB8fDB8fHww', 'ตีครีมสดสไตล์ญี่ปุ่น ยัดไส้โดนัทนมสดเนื้อเบานุ่มละลายในปาก'),
(10, 'ชีสเค้กหน้าไหม้สไตล์บาสก์เข้มข้น', 'เชฟ ปาริชาต', 'เริ่มต้น',   3200, 10, 'เค้กและขนมหวาน',     '🎂', 'https://images.unsplash.com/photo-1635327173748-5fe11b795610?w=500&auto=format&fit=crop&q=60&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxzZWFyY2h8NHx8UmljaCUyMEJhc3F1ZSUyMGJ1cm50JTIwY2hlZXNlY2FrZXxlbnwwfHwwfHx8MA%3D%3D', 'อบชีสเค้กหน้าไหม้เนื้อครีมชีสเนียนนุ่มกึ่งลาวา พร้อมซอสเบอร์รีโฮมเมด'),
(11, 'คลาสสิกฟรุตทาร์ตสไตล์ฝรั่งเศส', 'เชฟ พงศธร', 'ระดับกลาง', 3400, 10, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://images.unsplash.com/photo-1620980776848-84ac10194945?w=500&auto=format&fit=crop&q=60&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxzZWFyY2h8Mnx8Q2xhc3NpYyUyMEZyZW5jaC1zdHlsZSUyMGZydWl0JTIwdGFydHxlbnwwfHwwfHx8MA%3D%3D', 'ทำแป้งทาร์ตกรอบร่วนสไตล์ฝรั่งเศส (Pâte Sablée) ครีมคัสตาร์ดวานิลลาแท้และผลไม้สด'),
(12, 'ขนมปังบริยอชเนยสดฝรั่งเศส', 'เชฟ ธนวัฒน์', 'ระดับกลาง', 2800, 12, 'ขนมปังอบ',            '🍞', 'https://images.unsplash.com/photo-1552056413-b8b5eed0170b?w=500&auto=format&fit=crop&q=60&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxzZWFyY2h8Mnx8RnJlbmNoJTIwYnJpb2NoZSUyMGJyZWFkJTIwd2l0aCUyMGJ1dHRlcnxlbnwwfHwwfHx8MA%3D%3D', 'เรียนรู้วิธีนวดแป้งผสมเนยสดแท้สไตล์ Brioche Nanterre ให้ได้เนื้อสัมผัสใยไหมฉีกมือหอมละมุน'),
(13, 'ขนมปังเบเกิลสไตล์นิวยอร์ก', 'เชฟ ธนวัฒน์', 'เริ่มต้น',   2400, 12, 'ขนมปังอบ',            '🍞', 'https://plus.unsplash.com/premium_photo-1720070416636-0e5ef67d3862?w=500&auto=format&fit=crop&q=60&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxzZWFyY2h8MXx8TmV3JTIwWW9yayUyMHN0eWxlJTIwYmFnZWx8ZW58MHx8MHx8fDA%3D', 'ฝึกทำเบเกิลเนื้อหนุบหนับตามแบบฉบับนิวยอร์กแท้ ตั้งแต่การต้มแป้งจนถึงการอบโรยงาและกระเทียม'),
(14, 'ขนมปังนมฮอกไกโดและโชกุปัง', 'เชฟ ธนวัฒน์', 'เริ่มต้น',   2600, 12, 'ขนมปังอบ',            '🍞', 'https://thebakeanista.com/wp-content/uploads/2020/05/Japanese-Milk-Bread-Crumbs-e1604224456391-1400x800.jpg', 'สัมผัสความนุ่มยืดแบบ Yudane เคล็ดลับขนมปังนมฮอกไกโดและโชกุปังแสนอร่อย'),
(15, 'บาแก็ตฝรั่งเศสแบบดั้งเดิม', 'เชฟ ธนวัฒน์', 'ระดับกลาง', 2300, 15, 'ขนมปังอบ',            '🍞', 'https://plus.unsplash.com/premium_photo-1677686707023-9ac1e4f75a87?q=80&w=687&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D', 'ฝึกอบบาแก็ตฝรั่งเศสแท้ๆ (Baguette de Tradition) ให้เปลือกนอกบางกรอบ เนื้อในนุ่มเป็นโพรงสวย'),
(16, 'ซีบัคธอร์นซาวร์โดว์และธัญพืช', 'เชฟ ธนวัฒน์', 'ระดับสูง',  2700, 10, 'ขนมปังอบ',            '🍞', 'https://omegafruit.ca/wp-content/uploads/2024/10/Seaberry-apple-nut-bread-close-up-.jpg.webp', 'ยกระดับซาวร์โดว์ด้วยผลซีบัคธอร์นเปรี้ยวอมหวาน และธัญพืชโฮลเกรนคั่วหอมหลากชนิด'),
(17, 'ขนมปังไรย์เยอรมันคลาสสิก', 'เชฟ ธนวัฒน์', 'ระดับกลาง', 2500, 12, 'ขนมปังอบ',            '🍞', 'https://images.unsplash.com/photo-1509440159596-0249088772ff?q=80&w=1172&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D', 'ขนมปังไรย์สไตล์เยอรมันแท้เนื้อแน่น เสริมสุขภาพด้วยเมล็ดฟักทองและดอกทานตะวัน'),
(18, 'ซินนามอนโรลเคลือบครีมชีสฟรอสติ้ง', 'เชฟ นภัสสร', 'เริ่มต้น',   2600, 15, 'ขนมปังอบ',            '🍞', 'https://images.unsplash.com/photo-1686207855146-c3ffe2166d40?w=500&auto=format&fit=crop&q=60&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxzZWFyY2h8N3x8Q2lubmFtb24lMjByb2xscyUyMGNvYXRlZCUyMHdpdGglMjBjcmVhbSUyMGNoZWVzZSUyMGZyb3N0aW5nfGVufDB8fDB8fHww', 'ทำขนมปังซินนามอนโรลหอมอบเชยเนื้อฉ่ำ นุ่มนวล เคลือบด้วยครีมชีสฟรอสติ้งเข้มข้นรสเลิศ'),
(19, 'บอมโบโลนีโดนัทอิตาเลียนไส้คัสตาร์ด', 'เชฟ นภัสสร', 'เริ่มต้น',   3100, 12, 'โดนัทและฟริตเตอร์',   '🍩', 'https://nombeah.com/wp-content/uploads/2024/09/Bomboloni-3.jpg.avif', 'ฝึกปั้นและทอดบอมโบโลนี (Bomboloni) โดนัทกลมไม่มีรูสไตล์อิตาลี คลุกน้ำตาลทรายและบีบไส้ครีมคัสตาร์ดเนียนละมุน'),
(20, 'โดนัทเค้กช็อกโกแลตสไตล์โบราณ', 'เชฟ นภัสสร', 'เริ่มต้น',   2500, 15, 'โดนัทและฟริตเตอร์',   '🍩', 'https://plus.unsplash.com/premium_photo-1672846027103-a50797886f99?w=500&auto=format&fit=crop&q=60&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxzZWFyY2h8MXx8VmludGFnZSUyMHN0eWxlJTIwY2hvY29sYXRlJTIwZG9udXQlMjBjYWtlfGVufDB8fDB8fHww', 'โดนัทช็อกโกแลตเนื้อแน่นแบบ Old Fashioned รสเข้มข้น กรอบนอก นุ่มหนึบด้านใน'),
(21, 'ชูร์โรสสเปนและซอสดาร์กช็อกโกแลต', 'เชฟ พงศธร', 'เริ่มต้น',   2600, 15, 'โดนัทและฟริตเตอร์',   '🍩', 'https://plus.unsplash.com/premium_photo-1713962962200-e33e90cb2c60?w=500&auto=format&fit=crop&q=60&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxzZWFyY2h8MXx8U3BhbmlzaCUyMGNodXJyb3MlMjB3aXRoJTIwZGFyayUyMGNob2NvbGF0ZSUyMHNhdWNlfGVufDB8fDB8fHww', 'บีบและทอดปาท่องโก๋สเปน (Churros) ให้เหลืองทอง กรอบอร่อย คลุกอบเชยน้ำตาล และทำดิปร้อนดาร์กช็อกโกแลตแท้'),
(22, 'ครอฟเฟิลและโมจิโดนัทสองรสชาติ', 'เชฟ นภัสสร', 'เริ่มต้น',   2800, 12, 'โดนัทและฟริตเตอร์',   '🍩', 'https://s3-media0.fl.yelpcdn.com/bphoto/acAwKa5qfWV5aLTExGQ-5g/o.jpg', 'ผสมผสานครัวซองต์วาฟเฟิลสไตล์ฮิต และทำโดนัทแป้งโมจิหนุบหนับสไตล์ญี่ปุ่นเคลือบมัทฉะและสตรอว์เบอร์รี'),
(23, 'โดนัทเคลือบเมเปิ้ลเบคอนเค็มหวาน', 'เชฟ นภัสสร', 'ระดับกลาง', 3000, 12, 'โดนัทและฟริตเตอร์',   '🍩', 'https://images.unsplash.com/photo-1585459441171-70a603cd5e46?w=500&auto=format&fit=crop&q=60&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxzZWFyY2h8M3x8U3dlZXQlMjBhbmQlMjBzYXZvcnklMjBtYXBsZSUyMGJhY29uJTIwZ2xhemVkJTIwZG9udXR8ZW58MHx8MHx8fDA%3D', 'ทำโดนัทเคลือบไซรัปเมเปิ้ลโรยด้วยเบคอนกรอบคั่ว รสสัมผัสเค็มหวานเข้ากันอย่างลงตัวแบบคาเฟ่อเมริกา'),
(24, 'บริยอชโดนัทไส้เลมอนเคิร์ด', 'เชฟ ปาริชาต', 'ระดับกลาง', 3200, 10, 'โดนัทและฟริตเตอร์',   '🍩', 'https://plus.unsplash.com/premium_photo-1716918179075-d81daab96c4e?q=80&w=1170&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D', 'สร้างสรรค์โดนัทพรีเมียมจากแป้งบริยอชหอมเนย สอดไส้ครีมเลมอนเคิร์ดเปรี้ยวอมหวาน หอมผิวเลมอนเหลืองสดชื่น'),
(25, 'สตรูปวาฟเฟิลสไตล์ดัตช์ดั้งเดิม', 'เชฟ นภัสสร', 'ระดับกลาง', 2700, 12, 'โดนัทและฟริตเตอร์',   '🍩', 'https://plus.unsplash.com/premium_photo-1664478254358-fb8ce668dca6?q=80&w=991&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D', 'ทำวาฟเฟิลแผ่นบางเฉียบสไตล์เนเธอร์แลนด์ (Stroopwafel) รีดร้อนและสอดไส้ไซรัปคาราเมลหอมเนยน้ำตาลอบเชย'),
(26, 'โดนัทวีแกนเพื่อสุขภาพปราศจากกลูเตน', 'เชฟ นภัสสร', 'เริ่มต้น',   2800, 12, 'โดนัทและฟริตเตอร์',   '🍩', 'https://images.unsplash.com/photo-1631397833242-fc6213046352?q=80&w=687&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D', 'โดนัทอบไร้แป้งสาลีและนมเนยไข่ รสสัมผัสนุ่มเบาเพื่อสุขภาพที่ดีเคลือบน้ำตาลมะพร้าวออร์แกนิก'),
(27, 'สตรอว์เบอร์รีชอร์ตเค้กสไตล์ญี่ปุ่น', 'เชฟ ปาริชาต', 'เริ่มต้น',   3500, 10, 'เค้กและขนมหวาน',     '🎂', 'https://images.unsplash.com/photo-1627308595171-d1b5d67129c4?w=500&auto=format&fit=crop&q=60&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxzZWFyY2h8M3x8SmFwYW5lc2Utc3R5bGUlMjBzdHJhd2JlcnJ5JTIwc2hvcnRjYWtlfGVufDB8fDB8fHww', 'เรียนรู้วิธีอบสปันจ์เค้ก (Sponge Cake) ให้เบาฟูนุ่มสไตล์โตเกียว ประกอบชั้นครีมสดและสตรอว์เบอร์รีรสฉ่ำหวาน'),
(28, 'ช็อกโกแลตมูสลาวาและสตรอว์เบอร์รี', 'เชฟ พงศธร', 'ระดับกลาง', 3300, 12, 'เค้กและขนมหวาน',     '🧁', 'https://images.unsplash.com/photo-1621792907789-666f0e69ea03?q=80&w=687&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D', 'ทำเค้กลาวาช็อกโกแลตอุ่นๆ ไส้ไหล คู่กับมูสเบลเยียมช็อกโกแลตเนื้อเนียน และผลสตรอว์เบอร์รีสด'),
(29, 'เค้กแครอทครีมชีสและถั่วพีแคน', 'เชฟ ปาริชาต', 'เริ่มต้น',   2900, 12, 'เค้กและขนมหวาน',     '🎂', 'https://plus.unsplash.com/premium_photo-1715030176164-7ba7e3298856?q=80&w=687&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D', 'เค้กแครอทเนื้อชุ่มชื้นอัดแน่นด้วยวอลนัทและลูกเกด ปาดหน้าครีมชีสรสเปรี้ยวหวานมัน ตกแต่งด้วยถั่วพีแคนคั่ว'),
(30, 'เค้กเลมอนบลูเบอร์รีป๊อปปี้ซีด', 'เชฟ ปาริชาต', 'เริ่มต้น',   3100, 10, 'เค้กและขนมหวาน',     '🎂', 'https://plus.unsplash.com/premium_photo-1714662390452-90962d05cbf4?q=80&w=688&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D', 'เค้กเนยสดเลมอนผสมเม็ดป๊อปปี้ซีด เคี้ยวกรุบกรอบ สอดไส้ซอสบลูเบอร์รีป่าโฮมเมดราดไอซิ่งเกลซเลมอนรสเปรี้ยวหวานสะใจ'),
(31, 'ทีรามิสุสไตล์อิตาเลียนดั้งเดิม', 'เชฟ พงศธร', 'ระดับกลาง', 3400, 12, 'เค้กและขนมหวาน',     '🧁', 'https://images.unsplash.com/photo-1704742205361-8d532d9d7e2e?q=80&w=765&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D', 'ทำทีรามิสุแสนอร่อยตามสูตรอิตาลีดั้งเดิม ตั้งแต่ทำเลดี้ฟิงเกอร์เอง ซึมซับกาแฟเอสเพรสโซ่เข้มข้นสลับชั้นมาสคาร์โปนครีมสด'),
(32, 'เค้กเรดเวลเวตพรีเมียมบัตเตอร์ครีม', 'เชฟ ปาริชาต', 'ระดับกลาง', 3200, 10, 'เค้กและขนมหวาน',     '🎂', 'https://images.unsplash.com/photo-1714386148315-2f0e3eebcd5a?q=80&w=736&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D', 'เค้กกำมะหยี่สีแดงรสโกโก้อ่อนๆ สลับชั้นครีมชีสฟรอสติ้งเนียนหนานุ่ม ตกแต่งเค้กให้สวยหรูแนววิคตอเรียน'),
(33, 'นิวยอร์กชีสเค้กซอสสตรอว์เบอร์รี', 'เชฟ ปาริชาต', 'ระดับสูง',  3600, 10, 'เค้กและขนมหวาน',     '🎂', 'https://drivemehungry.com/wp-content/uploads/2022/07/strawberry-cheesecake-8.jpg', 'เจาะลึกเทคนิคการอบชีสเค้กแบบนิวยอร์กสตูดิโอให้หน้าเรียบเนียน เนื้อแน่นนุ่มละมุนลิ้น ราดด้วยซอสสตรอว์เบอร์รีป่ารสเปรี้ยวหวานตัดเลี่ยน'),
(34, 'ชูครีมและเอแคลร์ไส้คัสตาร์ด', 'เชฟ ปาริชาต', 'เริ่มต้น',   3000, 12, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://plus.unsplash.com/premium_photo-1764355119672-d37d2ba8efdb?q=80&w=687&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D', 'ฝึกทำแป้งพัฟชู (Choux Pastry) ให้ฟูกลวงสวย ทำครีมคัสตาร์ดกลิ่นวานิลลาฝักแท้ บีบไส้ชูครีมและราดช็อกโกแลตบนหน้าเอแคลร์'),
(35, 'มิลเฟยพัฟพาสทรีและครีมคัสตาร์ด', 'เชฟ พงศธร', 'ระดับสูง',  3700, 10, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://images.unsplash.com/photo-1593424731252-a846f98af7e6?q=80&w=687&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D', 'ท้าทายฝีมือกับ Mille-Feuille การพับแป้งพัฟให้บางเฉียบกรอบกรุบเป็นร้อยชั้น สอดสลับชั้นครีมมัสลินวานิลลาหอมหวานหรูหรา'),
(36, 'คานเล่สไตล์บอร์โดและเหล้ารัม', 'เชฟ พงศธร', 'ระดับสูง',  3200, 10, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://www.tasteatlas.com/images/dishes/62f83e07c05a47f9951a2dfbd32db73f.jpg?mw=1300', 'ฝึกทำ Canelés ขนมฝรั่งเศสโบราณ อบในพิมพ์ทองแดงเคลือบไขผึ้งแท้ (Beeswax) ให้ผิวเกรียมหอมคาราเมลด้านนอก เนื้อในนุ่มฉ่ำหอมเหล้ารัมและวานิลลา'),
(37, 'ฟินันเซียและมาดแลนเนยสีน้ำตาล', 'เชฟ ปาริชาต', 'เริ่มต้น',   2900, 12, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://www.foodnetwork.com/content/dam/images/food/fullset/2011/8/11/0/MN0505H_brown-butter-madeleines_s4x3.jpg', 'หัดเคี่ยวเนยสีน้ำตาล (Beurre Noisette) อบขนมฝรั่งเศสชิ้นจิ๋วทรงเปลือกหอยและแท่งทองให้ฟูนุ่มหอมกลิ่นถั่วคั่วตามสูตรดั้งเดิม'),
(38, 'คลาสสิกแอปเปิ้ลทาร์ตตาแต็ง', 'เชฟ พงศธร', 'ระดับกลาง', 3300, 10, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://images.unsplash.com/photo-1624299831638-82c15fcafd2b?q=80&w=687&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D', 'ทำทาร์ตแอปเปิ้ลกลับหัวสไตล์ฝรั่งเศสโบราณ (Tarte Tatin) นำแอปเปิ้ลไปเคี่ยวคาราเมลก่อนหุ้มด้วยแป้งพายกรอบเหลืองอร่อย'),
(39, 'ขนมปังควิญอามานเนยเค็มพรีเมียม', 'เชฟ พงศธร', 'ระดับสูง',  3600, 10, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://imagesvc.meredithcorp.io/v3/mm/image?url=https%3A%2F%2Fstatic.onecms.io%2Fwp-content%2Fuploads%2Fsites%2F43%2F2022%2F06%2F19%2F6440688-kouign-amann-Chef-John-1x1-1.jpg&q=60&c=sc&poi=auto&orient=true&h=512', 'ห่อพับเนยเค็ม (Kouign-Amann) และน้ำตาลให้สลับร้อยชั้น สปริงเนยเยิ้มผิวเคลือบคาราเมลกรอบแสนดึงดูดใจ'),
(40, 'พัฟพาสทรีไส้แอปเปิ้ลฝรั่งเศส', 'เชฟ พงศธร', 'ระดับกลาง', 3100, 12, 'เบเกอรี่ฝรั่งเศส',    '🥐', 'https://www.marcellinaincucina.com/wp-content/uploads/2021/04/puff-pastry-apple-tart-1-3.jpg', 'อบพายแป้งพัฟพาสทรีสอดไส้แอปเปิ้ลซอสบดหอมหวาน (Chausson aux Pommes) สลักลายดอกไม้สวยงามแบบดั้งเดิม');
